// TokenValidator handles token validation for service mesh
type TokenValidator struct {
	mu              sync.RWMutex
	sharedSecret    []byte
	trustedIssuers  map[string]bool
	allowedServices map[string][]string // service -> allowed permissions
	revokedTokens   map[string]time.Time
}

// NewTokenValidator creates a new token validator
func NewTokenValidator(secret []byte) *TokenValidator {
	tv := &TokenValidator{
		sharedSecret: secret,
		trustedIssuers: map[string]bool{
			"mesh-control-plane": true,
			"service-registry":   true,
		},
		allowedServices: map[string][]string{
			"frontend-service":  {"read", "write"},
			"backend-service":   {"read", "write", "admin"},
			"analytics-service": {"read"},
			"health-checker":    {"health"},
		},
		revokedTokens: make(map[string]time.Time),
	}

	// Start background cleanup of expired revoked tokens
	go tv.cleanupRevokedTokens()

	return tv
}

func (tv *TokenValidator) cleanupRevokedTokens() {
	ticker := time.NewTicker(5 * time.Minute)
	defer ticker.Stop()
	for range ticker.C {
		tv.mu.Lock()
		now := time.Now()
		for tokenHash, expiry := range tv.revokedTokens {
			if now.After(expiry) {
				delete(tv.revokedTokens, tokenHash)
			}
		}
		tv.mu.Unlock()
	}
}

// RevokeToken adds a token to the revocation list
func (tv *TokenValidator) RevokeToken(tokenSignature string, expiry time.Time) {
	tv.mu.Lock()
	defer tv.mu.Unlock()
	tv.revokedTokens[tokenSignature] = expiry
}

// isTokenRevoked checks if a token has been revoked
func (tv *TokenValidator) isTokenRevoked(tokenSignature string) bool {
	tv.mu.RLock()
	defer tv.mu.RUnlock()
	_, revoked := tv.revokedTokens[tokenSignature]
	return revoked
}

// ValidateToken validates a service mesh token and returns claims
func (tv *TokenValidator) ValidateToken(token string) (*TokenClaims, error) {
	if len(token) == 0 {
		return nil, fmt.Errorf("empty token")
	}

	// Limit token length to prevent abuse
	if len(token) > 4096 {
		return nil, fmt.Errorf("token exceeds maximum length")
	}

	// Token format: <service_id>.<issuer>.<audience>.<issued_at>.<expires_at>.<permissions>.<signature>
	parts := strings.Split(token, ".")
	if len(parts) != 7 {
		return nil, fmt.Errorf("invalid token format")
	}

	serviceID := parts[0]
	issuer := parts[1]
	audience := parts[2]
	issuedAtStr := parts[3]
	expiresAtStr := parts[4]
	permissionsStr := parts[5]
	signature := parts[6]

	// Validate input fields don't contain unexpected characters
	if !isAlphanumericDash(serviceID) || !isAlphanumericDash(issuer) || !isAlphanumericDash(audience) {
		return nil, fmt.Errorf("invalid characters in token fields")
	}

	// Verify signature using HMAC-SHA256 with constant-time comparison
	payload := strings.Join(parts[:6], ".")
	expectedSig := tv.computeHMAC([]byte(payload))

	sigBytes, err := hex.DecodeString(signature)
	if err != nil {
		return nil, fmt.Errorf("invalid signature encoding")
	}

	if !hmac.Equal(sigBytes, expectedSig) {
		return nil, fmt.Errorf("invalid token signature")
	}

	// Check if token is revoked
	if tv.isTokenRevoked(signature) {
		return nil, fmt.Errorf("token has been revoked")
	}

	// Parse timestamps
	issuedAt, err := time.Parse(time.RFC3339, issuedAtStr)
	if err != nil {
		return nil, fmt.Errorf("invalid issued_at timestamp")
	}

	expiresAt, err := time.Parse(time.RFC3339, expiresAtStr)
	if err != nil {
		return nil, fmt.Errorf("invalid expires_at timestamp")
	}

	now := time.Now()

	// Check token is not from the future (with small clock skew allowance)
	clockSkew := 30 * time.Second
	if issuedAt.After(now.Add(clockSkew)) {
		return nil, fmt.Errorf("token issued in the future")
	}

	// Check token expiration
	if now.After(expiresAt.Add(clockSkew)) {
		return nil, fmt.Errorf("token has expired")
	}

	// Check token isn't too old (max lifetime 24 hours for service mesh tokens)
	maxLifetime := 24 * time.Hour
	if expiresAt.Sub(issuedAt) > maxLifetime {
		return nil, fmt.Errorf("token lifetime exceeds maximum allowed")
	}

	// Validate issuer
	tv.mu.RLock()
	trusted := tv.trustedIssuers[issuer]
	tv.mu.RUnlock()
	if !trusted {
		return nil, fmt.Errorf("untrusted token issuer: %s", issuer)
	}

	// Validate audience matches this service
	if audience != "mesh-service" && audience != "*" {
		return nil, fmt.Errorf("token audience mismatch")
	}

	// Parse permissions
	permissions := strings.Split(permissionsStr, ",")
	for _, p := range permissions {
		if !isAlphanumericDash(p) {
			return nil, fmt.Errorf("invalid permission format")
		}
	}

	// Validate service has the claimed permissions
	tv.mu.RLock()
	allowedPerms, serviceExists := tv.allowedServices[serviceID]
	tv.mu.RUnlock()

	if !serviceExists {
		return nil, fmt.Errorf("unknown service: %s", serviceID)
	}

	for _, perm := range permissions {
		if !containsString(allowedPerms, perm) {
			return nil, fmt.Errorf("service %s does not have permission: %s", serviceID, perm)
		}
	}

	return &TokenClaims{
		ServiceID:   serviceID,
		Issuer:      issuer,
		Audience:    audience,
		IssuedAt:    issuedAt,
		ExpiresAt:   expiresAt,
		Permissions: permissions,
	}, nil
}

func (tv *TokenValidator) computeHMAC(data []byte) []byte {
	mac := hmac.New(sha256.New, tv.sharedSecret)
	mac.Write(data)
	return mac.Sum(nil)
}

// GenerateToken creates a signed token for testing/internal use
func (tv *TokenValidator) GenerateToken(serviceID, issuer, audience string, permissions []string, duration time.Duration) string {
	now := time.Now().UTC()
	expires := now.Add(duration)

	payload := fmt.Sprintf("%s.%s.%s.%s.%s.%s",
		serviceID,
		issuer,
		audience,
		now.Format(time.RFC3339),
		expires.Format(time.RFC3339),
		strings.Join(permissions, ","),
	)

	sig := tv.computeHMAC([]byte(payload))
	return fmt.Sprintf("%s.%s", payload, hex.EncodeToString(sig))
}

// --- Rate limiter ---

type rateLimiter struct {
	mu       sync.Mutex
	requests map[string][]time.Time
	limit    int
	window   time.Duration
}

func newRateLimiter(limit int, window time.Duration) *rateLimiter {
	rl := &rateLimiter{
		requests: make(map[string][]time.Time),
		limit:    limit,
		window:   window,
	}
	go rl.cleanup()
	return rl
}

func (rl *rateLimiter) cleanup() {
	ticker := time.NewTicker(1 * time.Minute)
	defer ticker.Stop()
	for range ticker.C {
		rl.mu.Lock()
		cutoff := time.Now().Add(-rl.window)
		for key, times := range rl.requests {
			var valid []time.Time
			for _, t := range times {
				if t.After(cutoff) {
					valid = append(valid, t)
				}
			}
			if len(valid) == 0 {
				delete(rl.requests, key)
			} else {
				rl.requests[key] = valid
			}
		}
		rl.mu.Unlock()
	}
}

func (rl *rateLimiter) Allow(key string) bool {
	rl.mu.Lock()
	defer rl.mu.Unlock()

	now := time.Now()
	cutoff := now.Add(-rl.window)

	var valid []time.Time
	for _, t := range rl.requests[key] {
		if t.After(cutoff) {
			valid = append(valid, t)
		}
	}

	if len(valid) >= rl.limit {
		rl.requests[key] = valid
		return false
	}

	rl.requests[key] = append(valid, now)
	return true
}

