func (s *meshServer) ProcessRequest(ctx context.Context, req *ServiceRequest) (*ServiceResponse, error) {
	claims, ok := claimsFromContext(ctx)
	if !ok {
		return nil, status.Error(codes.Internal, "authentication claims not found in context")
	}

	// Check specific permission for this endpoint
	if !hasPermission(claims, "write") {
		return nil, status.Errorf(codes.PermissionDenied, "service %s lacks 'write' permission", claims.ServiceID)
	}

	log.Printf("Processing request from service=%s request_id=%s", claims.ServiceID, req.RequestID)

	return &ServiceResponse{
		Status:    "OK",
		Data:      []byte(fmt.Sprintf("Processed by mesh-service for %s", claims.ServiceID)),
		RequestID: req.RequestID,
	}, nil
}

func (s *meshServer) HealthCheck(ctx context.Context, req *ServiceRequest) (*ServiceResponse, error) {
	claims, ok := claimsFromContext(ctx)
	if !ok {
		return nil, status.Error(codes.Internal, "authentication claims not found in context")
	}

	if !hasPermission(claims, "health") && !hasPermission(claims, "read") {
		return nil, status.Errorf(codes.PermissionDenied, "service %s lacks health check permission", claims.ServiceID)
	}

	return &ServiceResponse{
		Status:    "HEALTHY",
		Data:      []byte("service is healthy"),
		RequestID: req.RequestID,
	}, nil
}

